import React from "react";
import "./CalendarGrid.css";
import events from "../data/events";

const CalendarGrid = () => {
  const year = 2025;
  const month = 11; // December (0-based index)

  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();

  const cells = [];

  // Empty cells before month start
  for (let i = 0; i < firstDay; i++) {
    cells.push(<div key={`empty-${i}`} className="day-cell empty"></div>);
  }

  // Actual days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = `${year}-${String(month + 1).padStart(2, "0")}-${String(day).padStart(2, "0")}`;

    const dayEvents = events.filter(e => e.date === dateStr);

    let eventClass = "";
    if (dayEvents.some(e => e.type === "holiday")) eventClass = "holiday";
    else if (dayEvents.some(e => e.type === "leave")) eventClass = "leave";
    else if (dayEvents.some(e => e.type === "birthday")) eventClass = "birthday";

    cells.push(
      <div key={day} className={`day-cell ${eventClass}`}>
        <span className="day-number">{day}</span>

        {dayEvents.map((e, index) => (
          <div key={index} className="event-text">
            {e.title}
          </div>
        ))}
      </div>
    );
  }

  return <div className="calendar-grid">{cells}</div>;
};

export default CalendarGrid;
